import { Pencil, Plus } from "lucide-react";
import React from "react";
import { getProduct } from "@/api_call/api";
import Link from "next/link";
import DeleteBtn from "@/app/components/admin components/DeleteBtn";

export default async function UserManagementTable() {
  const data = await getProduct();
  const Brands = data.data;
  console.log("console", Brands[0].brandId);
  // console.log(Brands.thumbnail)
  const meta = data.meta;
  // console.log(meta)
  return (
    <div className="p-6min-h-screen">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-semibold text-gray-800">Products</h1>
          <p className="text-sm text-gray-500 mt-1">Manage Products</p>
        </div>

        <Link href={"product/add"}>
          <button className="flex items-center gap-2 px-5 py-2.5 bg-orange-500 text-white rounded-xl shadow hover:shadow-md hover:scale-105 transition">
            <Plus size={18} />
            Add Brand
          </button>
        </Link>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full text-left border-collapse">
            {/* Table Head */}
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">
                  Image
                </th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">
                  Name
                </th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">
                  Category
                </th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">
                  Brand
                </th>
                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">
                  Stock
                </th>

                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-center">
                  Actions
                </th>
              </tr>
            </thead>

            {/* Table Body */}
            <tbody className="divide-y">
              {Brands.map((user) => (
                <tr
                  key={user._id}
                  className="hover:bg-gray-50 transition duration-150"
                >
                  {/* Image */}
                  <td className="px-6 py-4">
                    <img
                      src={`http://localhost:5000/product/${user?.thumbnail}`}
                      alt={user.name}
                      className="w-12 h-12 rounded-xl object-cover border"
                    />
                  </td>

                  {/* Name */}
                  <td className="px-6 py-4 text-sm font-semibold text-gray-800">
                    <div className="flex flex-wrap gap-2">
                      <span className="bg-gray-100 px-1 py-1  text-xs rounded-md">
                        {user.name}
                      </span>
                    </div>
                  </td>

                  {/* Category */}
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-2">
                      <span className="px-1 py-1 text-xs font-medium bg-indigo-100 text-indigo-700 rounded-full">
                        {user.categoryId.name}
                      </span>
                    </div>
                  </td>
                  {/* Brand */}
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-2">
                      <span className=" px-1 py-1 text-xs font-medium bg-indigo-100 text-indigo-700 rounded-full">
                        {user.brandId.name}
                      </span>
                    </div>
                  </td>

                  {/* status */}

                  <td className="p-4">
                    <Status
                      value={user.status}
                      type={"product"}
                      id={user._id}
                      feild={"status"}
                    />
                    <Status
                      value={user.is_home}
                      type={"product"}
                      id={user._id}
                      feild={"is_home"}
                    />
                    <Status
                      value={user.is_top}
                      type={"product"}
                      id={user._id}
                      feild={"is_top"}
                    />
                    <Status
                      value={user.is_popular}
                      type={"product"}
                      id={user._id}
                      feild={"is_popular"}
                    />
                    <Status
                      value={user.is_popular}
                      type={"product"}
                      id={user._id}
                      feild={"is_hot"}
                    />
                      <Status
                      value={user.is_popular}
                      type={"product"}
                      id={user._id}
                      feild={"is_best"}
                    />
                       <Status
                      value={user.is_popular}
                      type={"product"}
                      id={user._id}
                      feild={"stock"}
                    />
                  </td>

                  {/* Actions */}
                  <td className="px-6 py-4">
                    <div className="flex items-center justify-center gap-3">
                      <button className="p-2 rounded-lg hover:bg-blue-50 text-blue-600 hover:text-blue-800 transition">
                        <Link href={`/admin/brand/edit/${user.slug}`}>
                          <Pencil size={18} />
                        </Link>
                      </button>

                      <DeleteBtn id={user._id} type={"product"} />
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
